$ErrorActionPreference="Stop";$Root=Split-Path -Parent $PSScriptRoot;Push-Location $Root
try{if(Test-Path "db/migrations/024_*"){throw "migration 024 is permanently unused"};$m=@(Get-ChildItem db/migrations -Filter "052_*.sql");if($m.Count-ne 1-or$m[0].Name-ne"052_phase24e_support_bot_knowledge_base.sql"){throw "Phase24E requires migration 052 exactly once"};foreach($p in @("backend/src/support/knowledgeBase","backend/src/support/bot","backend/src/providers/nlu","docs/contracts/CONTRACT_SUPPORT_BOT_KB.md","apps/admin/src/pages/SupportKnowledgeBasePage.tsx")){if(-not(Test-Path $p)){throw "missing Phase24E artifact: $p"}};$nlu=Get-ChildItem backend/src/providers/nlu -Filter *.ts|Get-Content -Raw;if($nlu-match'externalProviderExecuted\s*:\s*true'){throw "external NLU success is forbidden"};$support=Get-ChildItem backend/src/support/knowledgeBase,backend/src/support/bot -Filter *.ts|Get-Content -Raw;if($support-match'(?im)\b(?:INSERT\s+INTO|UPDATE|DELETE\s+FROM)\s+(?:orders|payment_orders|dispatch_|aftersale_|ledger_|settlement_)'){throw "Bot/KB writes protected domain"};$outbox=Get-Content packages/types/src/eventOutbox.ts -Raw;if(-not$outbox.Contains("support.bot.handed_off")){throw "missing Bot handoff Outbox fact"}}finally{Pop-Location};Write-Host "check-phase24e-boundaries: passed"
